t.script:

(function () {
  const root = document.getElementById("t-root");
  const wsUrl = root.dataset.ws;
  const statusEl = document.getElementById("t-status");

  const term = new Terminal({
    cursorBlink: true, fontSize: 13,
    fontFamily: '"JetBrains Mono", Menlo, Consolas, monospace',
    theme: { background: "#0d1117", foreground: "#c9d1d9", cursor: "#58a6ff" },
  });
  let fit = null;
  try {
    fit = new FitAddon.FitAddon();
    term.loadAddon(fit);
  } catch (e) { fit = null; }
  term.open(document.getElementById("term"));
  function doFit() { try { if (fit) fit.fit(); } catch (e) {} }
  doFit();

  let ws;
  function connect() {
    ws = new WebSocket(wsUrl);
    ws.onopen = function () {
      root.className = "ok"; statusEl.textContent = "connected";
      sendResize();
      term.focus();
    };
    ws.onmessage = function (e) { term.write(e.data); };
    ws.onclose = function () { root.className = "down"; statusEl.textContent = "disconnected"; term.write("\r\n\x1b[33m[session closed]\x1b[0m\r\n"); };
    ws.onerror = function () { root.className = "down"; statusEl.textContent = "connection error"; };
  }
  function sendResize() {
    if (ws && ws.readyState === 1) ws.send(JSON.stringify({ t: "r", c: term.cols, r: term.rows }));
  }
  term.onData(function (d) { if (ws && ws.readyState === 1) ws.send(JSON.stringify({ t: "i", d: d })); });
  window.addEventListener("resize", function () { doFit(); sendResize(); });

  connect();
})();
